// ---- Step 1: merge all participants from all pages ----
const merged = [];

for (const item of $input.all()) {
  const page = item.json;
  if (Array.isArray(page.participants)) {
    merged.push(...page.participants);
  }
}

// Optional: debug
// console.log('Merged length:', merged.length);
// console.log('Merged participants:', JSON.stringify(merged, null, 2));

// ---- Step 2: aggregate time & rejoins per user ----
const userTime = {}; // { key: { totalMinutes, name, phone, sessions, email, participantId, rejoins } }
const seenEmails = new Set(); // To track rejoin counts

merged.forEach((p, index) => {
  // If no duration AND no join/leave time, skip
  if (!p.join_time && typeof p.duration !== 'number') return;

  // Skip user if no email
  if (!p.user_email || !p.user_email.trim()) return;

  // Build a very safe unique key based on email
  const key = p.user_email.trim().toLowerCase();

  if (!key) return;

  let diffMin;

  // Zoom duration is in seconds in your logs
  if (typeof p.duration === 'number') {
    diffMin = p.duration / 60;
  } else {
    const join = new Date(p.join_time);
    const leave = new Date(p.leave_time);
    if (isNaN(join) || isNaN(leave)) return;
    const diffMs = leave - join;
    diffMin = diffMs / 1000 / 60;
  }

  if (!userTime[key]) {
    userTime[key] = {
      totalMinutes: 0,
      name: p.name || '',
      phone: p.phone || '',
      sessions: 0,
      email: key,
      participantId: p.participant_user_id || p.id || p.user_id || '',
      rejoins: 0, // Initialize rejoins
    };
  }

  // Increment rejoin count if the email has been seen before
  if (seenEmails.has(key)) {
    userTime[key].rejoins += 1;
  } else {
    seenEmails.add(key);
  }

  userTime[key].totalMinutes += diffMin;
  userTime[key].sessions += 1;
});

// ---- Step 3: create result array ----
const result = Object.entries(userTime).map(([key, data]) => {
  const nameParts = (data.name || '').trim().split(/\s+/);
  const firstName = nameParts[0] || '';
  const lastName = nameParts.slice(1).join(' ') || '';

  return {
    user_email: data.email || '',                       // may be empty
    first_name: firstName || '',
    last_name: lastName || '',
    phone: data.phone || '',
    total_minutes: Math.max(1, Math.round(data.totalMinutes)),
    rejoins: Math.max(0, data.rejoins),
    participant_id: data.participantId || key,
  };
});

// ---- Step 4: add totals ----
const totalUsers = result.length;

return [
  {
    json: {
      total_users: totalUsers,
      user_time_report: result,
    },
  },
];

