// ---- Step 2: aggregate time & rejoins per user ----
const userTime = {}; // { key: { totalMinutes, name, phone, sessions, email, participantId } }

merged.forEach((p, index) => {
  // If no duration AND no join/leave time, skip
  if (!p.join_time && typeof p.duration !== 'number') return;

  // Skip user if no email
  if (!p.user_email || !p.user_email.trim()) return;

  // Build a very safe unique key
  const key =
    (p.participant_user_id && String(p.participant_user_id)) ||
    (p.id && String(p.id)) ||
    (p.user_id && String(p.user_id)) ||         // <- extra fallback
    (p.user_email && String(p.user_email.trim().toLowerCase())) || // <- check for email
    `idx_${index}`;                             // <- last resort fallback

  if (!key) return;

  let diffMin;

  // Zoom duration is in seconds in your logs
  if (typeof p.duration === 'number') {
    diffMin = p.duration / 60;
  } else {
    const join = new Date(p.join_time);
    const leave = new Date(p.leave_time);
    if (isNaN(join) || isNaN(leave)) return;
    const diffMs = leave - join;
    diffMin = diffMs / 1000 / 60;
  }

  if (!userTime[key]) {
    userTime[key] = {
      totalMinutes: 0,
      name: p.name || '',
      phone: p.phone || '',
      sessions: 0,
      email: (p.user_email || '').trim().toLowerCase(),
      participantId: p.participant_user_id || p.id || p.user_id || '',
    };
  }

  userTime[key].totalMinutes += diffMin;
  userTime[key].sessions += 1;
});

// ---- Step 3: create result array ----
const result = Object.entries(userTime).map(([key, data]) => {
  const nameParts = (data.name || '').trim().split(/\s+/);
  const firstName = nameParts[0] || '';
  const lastName = nameParts.slice(1).join(' ') || '';

