];

// =====================================================
// Calculate Engagement Analytics (RAW MINUTE LEVEL)
// No 5-minute bucketing. Frontend handles windows.
// =====================================================

// Step 1: Merge all participants
const allParticipants = [];
for (const item of $input.all()) {
  const page = item.json;
  if (Array.isArray(page.participants)) {
    allParticipants.push(...page.participants);
  }
}

if (allParticipants.length === 0) {
  return [{
    json: {
      success: false,
      error: "No participant data available",
      meeting_id: $item("0").$node["server oauth"].json["meeting_id"],
      meeting_name: $item("0").$node["server oauth"].json["meeting_name"],
      meeting_type: $item("0").$node["server oauth"].json["meeting_type"],
      interval_minutes: 1,
      meeting_duration_minutes: 0,
      meeting_start_time: null,
      meeting_end_time: null,
      total_unique_participants: 0,
      total_participant_records: 0,
      average_participation_minutes: 0,
      max_participation_minutes: 0,
      min_participation_minutes: 0,
      engagement_score: 0,
      average_retention: 0,
      peak_concurrent_users: 0,
      final_active_users: 0,
      total_joined: 0,
      total_left: 0,
      engagement_graph: {
        granularity: "minute",
        granularity_minutes: 1,
        labels: [],
        timestamps: [],
        active_participants: [],
        users_joined: [],
        users_left: []
      },
      user_time_report: []
    }
  }];
}

// Step 2: Find meeting bounds
let minJoin = null;
let maxLeave = null;

for (const p of allParticipants) {
  try {
    if (!p.join_time || !p.leave_time) continue;
    const join = new Date(p.join_time);
    const leave = new Date(p.leave_time);
    if (isNaN(join.getTime()) || isNaN(leave.getTime())) continue;
    if (leave <= join) continue;
    if (!minJoin || join < minJoin) minJoin = join;
    if (!maxLeave || leave > maxLeave) maxLeave = leave;
  } catch (e) {}
}

if (!minJoin || !maxLeave) {
  return [{
    json: {
      success: false,
      error: "Could not determine meeting duration",
      meeting_id: $item("0").$node["server oauth"].json["meeting_id"]
    }
  }];
}

const meetingDurationMs = maxLeave.getTime() - minJoin.getTime();
const meetingDurationMinutes = Math.max(Math.ceil(meetingDurationMs / 60000), 1);

// Step 3: Build minute-level labels and timestamps
const labels = [];
const timestamps = [];
for (let i = 0; i < meetingDurationMinutes; i++) {
  const hh = String(Math.floor(i / 60)).padStart(2, "0");
  const mm = String(i % 60).padStart(2, "0");
  labels.push(`${hh}:${mm}`);
  timestamps.push(new Date(minJoin.getTime() + i * 60000).toISOString());
}

// Step 4: Minute-by-minute tracking
const activeUsersPerMinute = new Array(meetingDurationMinutes).fill(0);
const joinedPerMinute = new Array(meetingDurationMinutes).fill(0);
const leftPerMinute = new Array(meetingDurationMinutes).fill(0);

const userTimeMap = {};
let totalDurationSec = 0;
let maxDurationSec = 0;
let minDurationSec = Infinity;

for (const p of allParticipants) {
  try {
    if (!p.join_time || !p.leave_time) continue;
    const joinTime = new Date(p.join_time);
    const leaveTime = new Date(p.leave_time);
    if (isNaN(joinTime.getTime()) || isNaN(leaveTime.getTime())) continue;
    if (leaveTime <= joinTime) continue;

    const rawDurationSec =
      typeof p.duration === "number" && p.duration > 0
        ? p.duration
        : Math.round((leaveTime.getTime() - joinTime.getTime()) / 1000);

    totalDurationSec += rawDurationSec;
    if (rawDurationSec > maxDurationSec) maxDurationSec = rawDurationSec;
    if (rawDurationSec < minDurationSec) minDurationSec = rawDurationSec;

    const startMinute = Math.max(
      0,
      Math.min(
        meetingDurationMinutes - 1,
        Math.floor((joinTime.getTime() - minJoin.getTime()) / 60000)
      )
    );
    const endMinuteExclusive = Math.max(
      startMinute + 1,
      Math.min(
        meetingDurationMinutes,
        Math.ceil((leaveTime.getTime() - minJoin.getTime()) / 60000)
      )
    );

    joinedPerMinute[startMinute]++;
    leftPerMinute[Math.min(endMinuteExclusive - 1, meetingDurationMinutes - 1)]++;

    for (let minute = startMinute; minute < endMinuteExclusive; minute++) {
      activeUsersPerMinute[minute]++;
    }

    // User time aggregation
    const email = (p.user_email || "").trim().toLowerCase();
    if (!email) continue;

    if (!userTimeMap[email]) {
      const nameParts = (p.name || "").trim().split(/\s+/);
      userTimeMap[email] = {
        user_email: email,
        first_name: nameParts[0] || "",
        last_name: nameParts.slice(1).join(" ") || "",
        phone: p.phone || "",
        total_minutes: 0,
        rejoins: 0,
        sessions: 0,
        participant_id: p.participant_user_id || p.id || p.user_id || "",
        attentiveness_score: p.attentiveness_score || ""
      };
    }
    userTimeMap[email].total_minutes += rawDurationSec / 60;
    userTimeMap[email].sessions += 1;
    userTimeMap[email].rejoins = Math.max(0, userTimeMap[email].sessions - 1);

  } catch (e) {}
}

// Step 5: Summary stats
const peakConcurrent = activeUsersPerMinute.length ? Math.max(...activeUsersPerMinute) : 0;
const finalActiveUsers = activeUsersPerMinute[activeUsersPerMinute.length - 1] || 0;
const totalJoined = joinedPerMinute.reduce((a, b) => a + b, 0);
const totalLeft = leftPerMinute.reduce((a, b) => a + b, 0);
const totalUniqueParticipants = Object.keys(userTimeMap).length;

const averageActive = activeUsersPerMinute.length
  ? activeUsersPerMinute.reduce((a, b) => a + b, 0) / activeUsersPerMinute.length
  : 0;

const engagementScore = peakConcurrent > 0
  ? Math.round((averageActive / peakConcurrent) * 10000) / 100
  : 0;

const averageRetention = totalUniqueParticipants > 0
  ? Math.round((averageActive / totalUniqueParticipants) * 10000) / 100
  : 0;

const avgDurationMin = allParticipants.length > 0
  ? Math.round((totalDurationSec / allParticipants.length / 60) * 100) / 100
  : 0;

// Step 6: User time report
const userTimeReport = Object.values(userTimeMap)
  .map(u => ({
    user_email: u.user_email,
    first_name: u.first_name,
    last_name: u.last_name,
    phone: u.phone,
    total_minutes: Math.max(1, Math.round(u.total_minutes)),
    rejoins: u.rejoins,
    participant_id: u.participant_id,
    attentiveness_score: u.attentiveness_score
  }))
  .sort((a, b) => b.total_minutes - a.total_minutes);

return [{
  json: {
    success: true,
    meeting_id: $item("0").$node["server oauth"].json["meeting_id"],
    meeting_name: $item("0").$node["server oauth"].json["meeting_name"],
    meeting_type: $item("0").$node["server oauth"].json["meeting_type"],

    interval_minutes: 1,
    meeting_duration_minutes: meetingDurationMinutes,
    meeting_start_time: minJoin.toISOString(),
    meeting_end_time: maxLeave.toISOString(),

    total_unique_participants: totalUniqueParticipants,
    total_participant_records: allParticipants.length,
    average_participation_minutes: avgDurationMin,
    max_participation_minutes: maxDurationSec > 0 ? Math.round(maxDurationSec / 60 * 100) / 100 : 0,
    min_participation_minutes: minDurationSec === Infinity ? 0 : Math.round(minDurationSec / 60 * 100) / 100,

    engagement_score: engagementScore,
    average_retention: averageRetention,
    peak_concurrent_users: peakConcurrent,
    final_active_users: finalActiveUsers,
    total_joined: totalJoined,
    total_left: totalLeft,

    engagement_graph: {
      granularity: "minute",
      granularity_minutes: 1,
      labels,
      timestamps,
      active_participants: activeUsersPerMinute,
      users_joined: joinedPerMinute,
      users_left: leftPerMinute
    },

    user_time_report: userTimeReport
  }
}];

