function sanitize(str, tag) {
  if (!str) return '';
  let s = String(str);
  const t = '$' + tag + '$';
  if (s.includes(t)) s = s.replace(new RegExp('\\$' + tag + '\\$', 'g'), '');
  return s;
}

const aiJson = data.overall_ai_analysis
  ? sanitize(JSON.stringify(data.overall_ai_analysis), 'ai')
  : null;

const momentsJson = sanitize(
  JSON.stringify(data.transcript_moments || []),
  'tm'
);

const transcriptSafe = sanitize(data.transcript_content || '', 'tx');

return [{
  json: {
    meeting_id: String(data.meeting_id || ''),
    overall_ai_analysis_json: aiJson,
    transcript_moments_json: momentsJson,
    transcript_content: transcriptSafe,
    transcript_available: true,
    transcript_download_url: null,
    status: 'COMPLETED'
  }
}];

const data = $input.first().json;

let aiResult = null;
try {
  let content = '';

  if (Array.isArray(data.output) && data.output.length > 0) {
    const msg = data.output[0];
    if (Array.isArray(msg.content) && msg.content.length > 0) {
      content = msg.content[0].text || '';
