const data = $input.first().json;

// Transcript text from Download Transcript1
const transcript = data.data || '';
const meetingId = $item("0").$node["server oauth"].json["meeting_id"];
const meetingName = $item("0").$node["server oauth"].json["meeting_name"];

let prompt = '';

if (transcript && transcript.length >= 100) {
  prompt =
    "ROLE\nYou are a senior webinar engagement analyst.\n\n" +
    "OBJECTIVE\nAnalyze the FULL transcript and produce time-based insights.\n\n" +
    "FULL TRANSCRIPT (ONLY SOURCE OF TRUTH)\n\"\"\"" +
    "\n" + transcript + "\n\"\"\"\n\n" +
    "HARD RULES (STRICT)\n" +
    "- Use ONLY the spoken words in the transcript.\n" +
    "- Do NOT assume slides, polls, Q&A, or visuals.\n" +
    "- Do NOT mention Zoom or technical issues.\n" +
    "- Every point MUST reference a specific time in MM:SS format.\n" +
    "- Every point MUST explain a clear cause and effect.\n\n" +
    "TASK 1 — KEY INSIGHTS\nWrite 2-4 bullet points.\n" +
    "Structure: \"At <MM:SS>, engagement <increased/decreased> because <specific reason>.\"\n\n" +
    "TASK 2 — RECOMMENDATIONS\nWrite 2-4 bullet points.\n" +
    "Structure: \"Instead of <what happened at <MM:SS>>, the speaker should <specific alternative>.\"\n\n" +
    "TASK 3 — TRANSCRIPT MOMENTS\n" +
    "Write 3-6 important moments from the transcript.\n" +
    "Each moment must have: time_seconds (integer), time_label (MM:SS), summary (1 sentence), recommendation (1 sentence).\n\n" +
    "OUTPUT FORMAT (STRICT JSON ONLY — no markdown, no extra text)\n" +
    "{\n" +
    "  \"key_insights\": [\"...\"],\n" +
    "  \"recommendations\": [\"...\"],\n" +
    "  \"transcript_moments\": [\n" +
    "    { \"time_seconds\": 600, \"time_label\": \"00:10\", \"summary\": \"...\", \"recommendation\": \"...\" }\n" +
    "  ]\n" +
    "}";
} else {
  prompt = 'Return this exact JSON: {"key_insights": ["Transcript was not available for this session."], "recommendations": ["Enable cloud recording with audio transcript to get AI-powered insights."], "transcript_moments": []}';
}

return [{
  json: {
    meeting_id: meetingId,
    meeting_name: meetingName,
    transcript_content: transcript,
    ai_prompt: prompt
  }
}];

const provider = (($item('0').$node['server oauth'].json.ai_provider) || 'openai').toLowerCase();
const apiKey = ($item('0').$node['server oauth'].json.ai_api_key) || '';
const prompt = $input.first().json.ai_prompt || '';

let text = '';
try {
  if (provider === 'openai') {
    const res = await fetch('https://api.openai.com/v1/chat/completions', {
      method: 'POST',
      headers: { 'Authorization': `Bearer ${apiKey}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({ model: 'gpt-4o-mini', messages: [{ role: 'user', content: prompt }] })
    });
    const r = await res.json();
    text = r.choices?.[0]?.message?.content || '';
  } else if (provider === 'anthropic') {
    const res = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: { 'x-api-key': apiKey, 'anthropic-version': '2023-06-01', 'Content-Type': 'application/json' },
      body: JSON.stringify({ model: 'claude-haiku-4-5-20251001', max_tokens: 2048, messages: [{ role: 'user', content: prompt }] })
    });
    const r = await res.json();
    text = r.content?.[0]?.text || '';
  } else if (provider === 'gemini') {
    const res = await fetch('https://generativelanguage.googleapis.com/v1beta/models/gemini-1.5-flash:generateContent', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'x-goog-api-key': apiKey },
      body: JSON.stringify({ contents: [{ parts: [{ text: prompt }] }] })
    });
    const r = await res.json();
    text = r.candidates?.[0]?.content?.parts?.[0]?.text || '';
  }
} catch (e) {
  text = JSON.stringify({ key_insights: ['AI call failed: ' + e.message], recommendations: [], transcript_moments: [] });
}

return [{ json: { text } }];

const data = $input.first().json;

function sanitize(str, tag) {
  if (!str) return '';
  let s = String(str);
  const t = '$' + tag + '$';
  if (s.includes(t)) s = s.replace(new RegExp('\\$' + tag + '\\$', 'g'), '');
  return s;
}

function sqlEsc(str) {
  if (!str) return '';
  return String(str).replace(/'/g, "''");
}

return [{
  json: {
    meeting_id: String(data.meeting_id || ''),
    meeting_name: sqlEsc(data.meeting_name || 'Untitled Meeting'),
    meeting_type: data.meeting_type || 0,
    meeting_start_time: data.meeting_start_time || null,
    meeting_end_time: data.meeting_end_time || null,
    meeting_duration_minutes: data.meeting_duration_minutes || 0,
    interval_minutes: 1,
    generated_at: new Date().toISOString(),
    data_source: 'zoom_api_raw',

    total_unique_participants: data.total_unique_participants || 0,
    total_participant_records: data.total_participant_records || 0,
    average_participation_minutes: data.average_participation_minutes || 0,
